import { env } from "@/env";
import type {
  CreateCustomerInput,
  CreatePaymentIntentInput,
  Customer,
  PayApiClient,
} from "@subfico/pay-js-sdk/api";
import {
  createPayApiClient,
  PAY_API_VERSION,
} from "@subfico/pay-js-sdk/api";
import { createServerOnlyFn } from "@tanstack/react-start";

function createSubfiPayClient(renderToken: string): PayApiClient {
  const pay = createPayApiClient({
    baseUrl: env.SUB_API_URL_BASE,
    headers: {
      "X-Api-Key": env.SUB_API_KEY,
    },
  });
  pay.use({
    onRequest({ request }) {
      request.headers.set("X-Render-Token", renderToken);
      request.headers.set("X-Idempotency-Key", crypto.randomUUID());
      return request;
    },
  });
  return pay;
}

async function findOrCreateCustomer(
  pay: PayApiClient,
  accountId: string,
  requestBody: CreateCustomerInput,
): Promise<Customer> {
  const { data, response } = await pay.POST("/customers", {
    params: {
      header: {
        "X-Api-Version": PAY_API_VERSION,
      },
    },
    body: {
      customer: {
        ...requestBody,
        account_id: requestBody.account_id ?? accountId,
      },
    },
  });
  if (data) {
    return data;
  }
  if (response.status === 422 && requestBody.email) {
    const list = await pay.GET("/customers", {
      params: {
        query: {
          email: requestBody.email,
          account_id: accountId,
        },
        header: {
          "X-Api-Version": PAY_API_VERSION,
        },
      },
    });
    const existing = list.data?.data?.[0];
    if (existing) {
      return existing;
    }
  }
  throw new Error("SubFi Pay: could not create or resolve customer");
}

export const createPaymentIntent = createServerOnlyFn(
  async ({
    customer,
    paymentIntent,
    renderToken,
  }: {
    customer: Customer;
    paymentIntent: CreatePaymentIntentInput;
    renderToken: string;
  }): Promise<string | undefined> => {
    const pay = createSubfiPayClient(renderToken);
    const accountId = env.SUB_ACCOUNT_ID;

    try {
      const customerRow: Customer = customer?.id
        ? customer
        : await findOrCreateCustomer(pay, accountId, customer);

      const { data, error } = await pay.POST("/payment_intents", {
        params: {
          header: {
            "X-Api-Version": PAY_API_VERSION,
            "X-Account-Id": accountId,
          },
        },
        body: {
          payment_intent: {
            ...paymentIntent,
            customer_id: customerRow.id,
          },
        },
      });

      if (error) {
        throw error;
      }
      return data?.token;
    } catch (error) {
      console.error("Payment failed:", error);
      throw error;
    }
  },
);

